"use client";
import React, { useState, useRef, useEffect, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import gsap from "gsap";
import { useGSAP } from "@gsap/react";
import { ScrollTrigger } from "gsap/ScrollTrigger";

import "./Projects.css";

import img11 from "../../assets/Image/img11.jpg";
import img2 from "../../assets/Image/img2.jpg";
import img10 from "../../assets/Image/img10.jpg";
import img4 from "../../assets/Image/img4.jpg";
import img5 from "../../assets/Image/img5.jpg";
import img13 from "../../assets/Image/img13.jpg";

gsap.registerPlugin(ScrollTrigger);

function Project() {
  const [activeIndex, setActiveIndex] = useState(null);
  const [loadedImages, setLoadedImages] = useState({});
  const container = useRef();

  const projects = useMemo(
    () => [
      {
        category: "Open Plan Offices",
        client: "Hotel Ponsonby:",
        title: "transforming a heritage building into a chic gastropub",
        tags: ["Cube™", "Etch™", "Frontier™", "Symphony®"],
        img1: img11,
        img2: img2,
      },
      {
        category: "Recording Studios and Radio",
        client: "Mediaworks:",
        title: "Capturing the rebellious soul of radio",
        tags: ["CubeT", "Quietspace® Panel"],
        img1: img10,
        img2: img4,
      },
      {
        category: "Hotel Lobbies and Foyers",
        client: "Custom Frontier™ system",
        title: "for Headingley Stadium's Emerald Suite",
        tags: ["Frontier™"],
        img1: img13,
        img2: img5,
      },
    ],
    []
  );

  useGSAP(
    () => {
      if (!container.current) return;

      const rows = container.current.querySelectorAll(".project-row");

      rows.forEach((row) => {
        gsap.fromTo(
          row,
          { "--slideX": "-101%" },
          {
            "--slideX": "0%",
            ease: "power3.out",
            scrollTrigger: {
              trigger: row,
              start: "top 85%",
              end: "top 40%",
              scrub: 1,
            },
          }
        );

        ScrollTrigger.create({
          trigger: row,
          start: "top 85%",
          onEnter: () => row.classList.add("active"),
          onLeaveBack: () => row.classList.remove("active"),
        });
      });

      const buttons =
        container.current.querySelectorAll(".btn-frame");

      buttons.forEach((btn) => {
        const strip = btn.querySelector(".btn-strip");
        const leftCircle = btn.querySelector(".side-left");
        const rightCircle = btn.querySelector(".side-right");

        const tl = gsap.timeline({ paused: true });

        tl.to(strip, {
          x: 0,
          duration: 0.6,
          ease: "power3.out",
        })
          .fromTo(
            leftCircle,
            { scale: 0.3, opacity: 0 },
            {
              scale: 1,
              opacity: 1,
              duration: 0.6,
              ease: "back.out(1.7)",
            },
            0.1
          )
          .to(
            rightCircle,
            { scale: 0, opacity: 0, duration: 0.3 },
            0
          );

        const enter = () => tl.play();
        const leave = () => tl.reverse();

        btn.addEventListener("mouseenter", enter);
        btn.addEventListener("mouseleave", leave);

        btn._gsapHandlers = { enter, leave };
      });

      return () => {
        ScrollTrigger.getAll().forEach((t) => t.kill());

        buttons.forEach((btn) => {
          if (btn._gsapHandlers) {
            btn.removeEventListener(
              "mouseenter",
              btn._gsapHandlers.enter
            );
            btn.removeEventListener(
              "mouseleave",
              btn._gsapHandlers.leave
            );
          }
        });
      };
    },
    { scope: container }
  );

  /* Refresh when activeIndex changes */
  useEffect(() => {
    setTimeout(() => {
      ScrollTrigger.refresh();
    }, 500);
  }, [activeIndex]);

  /* Preload images */
  useEffect(() => {
    projects.forEach((project) => {
      [project.img1, project.img2].forEach((img) => {
        const image = new Image();
        image.src = img;

        image.onload = () => {
          setLoadedImages((prev) => ({
            ...prev,
            [img]: true,
          }));

          ScrollTrigger.refresh();
        };
      });
    });
  }, [projects]);

  return (
    <section
      id="Project"
      className="project-section"
      ref={container}
    >
      <div className="project-content-wrapper">

        <div className="project-heading">
          <div className="heading-box">
            <h1>
              We partner with serious scaleups worldwide
            </h1>
            <p>
              Helping them scale faster and smarter.
            </p>
          </div>
        </div>

        {projects.map((project, index) => (
          <div key={index} className="project-row">

            <div className="project-grid">

              <div className="project-category">
                <span
                  className={`dot ${
                    activeIndex === index
                      ? "active"
                      : ""
                  }`}
                />
                {project.category}
              </div>

              <div className="project-content">
                <h3>{project.client}</h3>

                <p className="project-title">
                  {project.title}
                </p>

                <div className="project-tags">
                  {project.tags.map((tag, i) => (
                    <span key={i}>{tag}</span>
                  ))}
                </div>
              </div>

              {/* FIXED CLICK HANDLER */}

              <div className="project-actions">

                <div
                  className="btn-frame"
                  onClick={() => {
                    setActiveIndex(
                      activeIndex === index
                        ? null
                        : index
                    );

                    setTimeout(() => {
                      ScrollTrigger.refresh();
                    }, 500);
                  }}
                >

                  <div className="btn-strip">

                    <div className="circle side-left">
                      <div className="arrow"></div>
                    </div>

                    <div className="box">
                      {activeIndex === index
                        ? "Hide"
                        : "Show details"}
                    </div>

                    <div className="circle side-right">
                      <div className="arrow"></div>
                    </div>

                  </div>

                </div>

              </div>

              <div></div>

              {/* IMAGE 1 */}

              <AnimatePresence>
                {activeIndex === index && (
                  <motion.div
                    className="img-grid"
                    initial={{
                      opacity: 0,
                      scale: 0.9,
                      y: 40,
                    }}
                    animate={{
                      opacity: 1,
                      scale: 1,
                      y: 0,
                    }}
                    exit={{
                      opacity: 0,
                      scale: 0.95,
                      y: 20,
                    }}
                    transition={{
                      duration: 0.6,
                    }}
                  >

                    <img
                      src={project.img1}
                      alt=""
                      onLoad={() =>
                        ScrollTrigger.refresh()
                      }
                    />

                  </motion.div>
                )}
              </AnimatePresence>

              {/* IMAGE 2 */}

              <AnimatePresence>
                {activeIndex === index && (
                  <motion.div
                    className="img-grid"
                    initial={{
                      opacity: 0,
                      scale: 0.9,
                      y: 40,
                    }}
                    animate={{
                      opacity: 1,
                      scale: 1,
                      y: 0,
                    }}
                    exit={{
                      opacity: 0,
                      scale: 0.95,
                      y: 20,
                    }}
                    transition={{
                      duration: 0.6,
                      delay: 0.1,
                    }}
                  >

                    <img
                      src={project.img2}
                      alt=""
                      onLoad={() =>
                        ScrollTrigger.refresh()
                      }
                    />

                  </motion.div>
                )}
              </AnimatePresence>

            </div>

          </div>
        ))}

        <div className="project-bottom-row">

          <h2 className="project-big-title">
            What We've Built
          </h2>

          <div className="project-actions">

            <div className="btn-frame">

              <div className="btn-strip">

                <div className="circle side-left">
                  <div className="arrow"></div>
                </div>

                <div className="box">
                  View All Projects
                </div>

                <div className="circle side-right">
                  <div className="arrow"></div>
                </div>

              </div>

            </div>

          </div>

        </div>

      </div>

    </section>
  );
}

export default Project;